var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"부대 신설에 대한 제 이야기는 여기까지입니다. 장관님의 견해를 듣고 싶군요.","JPN":"部隊新設についての私の話はここまでです。長官のご意見をお聞かせください。","ENG":"That concludes my brief on the establishment of the new unit. I'd appreciate your insight on the matter, Mr. Secretary.","TWN":"關於新創部隊的事就是這些了，我想聽聽長官您的意見。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......그러니까 요약하면 대 침식전 전문의 새로운 부대를 창설하자는 이야기로군.","JPN":"……要するに、対侵食戦専門の新しい部隊を創設するって話だな。","ENG":"So basically you want to create a new unit specializing in anti-Corruption warfare.","TWN":"……簡單來講，就是建設一個新部隊專門進行侵蝕戰嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"そうです｡","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하지만 굳이 새로운 부대를 만들 필요가 있을까?","JPN":"だが、わざわざ新しい部隊を作る必要があるのか？","ENG":"But do we really need to create a whole new unit for that?","TWN":"不過有必要成立一個新的部隊嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"애초에 자네는 태스크포스 1 엔터프라이즈의 사령관이지 않나?","JPN":"そもそも君はタスクフォース1エンタープライズの司令官じゃないか？","ENG":"You're the commanding general of the TASKFORCE 1 Enterprise in the first place.","TWN":"妳從一開始就是第一特遣勢力企業的司令官不是嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"새로운 부대를 만들고 나면 예전 부대는 버릴 생각인가?","JPN":"新しい部隊を作るとなると、あの部隊は見捨てる気か？","ENG":"Are you going to abandon your current post once you create this new unit?","TWN":"成立新的部隊後，原來的部隊怎麼辦？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......잘 아시면서 그런 말씀을 하시는군요.","JPN":"……よくご存知なのに、そんなことをおっしゃるのですね。","ENG":"I'm sure you know better than that.","TWN":"……您真是明知故問啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"기함인 엔터프라이즈는 파손과 노후화가 심해서 도크에 들어간 지 오래고, 저와 도미닉을 제외한 주요 멤버들도 대부분 전역하거나 실종된 상황입니다.","JPN":"旗艦であるエンタープライズは破損や老朽化が激しく、ずっとドックに入ったままですし、私とドミニークを除いたメインメンバーのほとんどが、除隊したり失踪している状態です。","ENG":"The flagship Enterprise has been sitting on the dock for a while now due to serious damages and obsolescence. Most key members aside from Dominic and I have already retired or gone M.I.A.","TWN":"企業號艦船由於嚴重的損壞與老化，很早就進了船塢，而除了我和多明尼克之外，大部分成員不是失蹤就是退伍。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사실상 부대 해산 상황이라고 해도 크게 다르지 않겠죠.","JPN":"事実上、部隊解散と言っても過言ではありません。","ENG":"The unit has virtually been disbanded, really.","TWN":"事實上，就算解散部隊也不會有什麼差別。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그렇다고 해서 새로운 부대를 만들겠다는 건 너무 앞서간 이야기 같은데.","JPN":"そうだとしても、新しい部隊を作るって話は早すぎると思うが。","ENG":"Even so, creating a new unit sounds like a stretch.","TWN":"話雖如此，成立一個新的部隊好像有點太早了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"태스크포스 1을 재정비하는 것이 재정적으로도 이득이지 않나?","JPN":"タスクフォース1を立て直すことがコストの面でもいいんじゃないのか？","ENG":"Wouldn't it make more sense fiscally to put the TASKFORCE 1 back in shape instead?","TWN":"重組第1特遣勢力在財政上也有好處吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"물론 그렇습니다만, 때로는 손해를 감수해야 할 때도 있는 법이죠.","JPN":"もちろんそうですが、時には損害を甘んじて受ける必要もあります。","ENG":"That may be the case, but sometimes it's worth bearing the extra cost.","TWN":"話是這麼說，但有時我們也得承擔一下損失。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"중요한 건 태스크포스 1은 결국 관리국에서 통제하는 무력집단이라는 점입니다.","JPN":"大事なのは、タスクフォース1は結局、管理局が統制する武力集団ということです。","ENG":"What's important is that TASKFORCE 1 is ultimately an armed organization controlled by the Administration.","TWN":"重要的是，第1特遣勢力終究還是由管理局掌控的武裝組織。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"말로는 협력관계라고 하지만 실질적으로는 관리국의 뜻대로 움직일 수밖에 없지요.","JPN":"協力関係とは言いますが、実質的には管理局の思うがままに動かざるをえません。","ENG":"Nominally, we're in a coordinating relationship with the Administration, but in truth, we must do as they say.","TWN":"雖然表面是合作關係，但實際上我們只能按照管理局的意願行動。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당장 엔터프라이즈의 현대화 개장 사업만 해도 필요한 기술 제공이 계속 미뤄지고 있지 않습니까?","JPN":"例えば、エンタープライズの現代化改装事業においても、必要な技術提供がずっと先送りになってきたのです。","ENG":"They're already stalling the technological transfer we need for the Enterprise's modernization project.","TWN":"即使企業號艦船需要立刻進行現代化改裝，他們不是也一直拖延沒有提供技術支援嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......현장에서 관리국의 태도를 그다지 유쾌하게 여기지 않는다는 건 나도 잘 알고 있네.","JPN":"……現場で管理局の態度をあまり面白く思ってないことは、私も知っているさ。","ENG":"I'm fully aware of how disgruntled our folks are about the Administration's attitude.","TWN":"……我也知道現在管理局的態度不是很友善。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하지만 그들은 적이 아니야. 너무 민감하게 받아들일 필요는 없다고 생각하는데......","JPN":"だが、彼らは敵ではない。そんなに過敏になる必要はないと思うが……","ENG":"But they are not the enemy. I don't think there's a need to react so sensitively about it...","TWN":"但他們不是敵人。我覺得沒必要這麼敏感……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"장관님, 언제까지 절 떠보실 생각입니까?","JPN":"長官、いつまで私に探りを入れるつもりですか？","ENG":"Sir, how much longer did you plan to keep testing me?","TWN":"長官，您打算試探我到什麼時候？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"애초에 장관님께서도 몇몇 의원들과 함께 몰래 관리국의 간섭을 받지 않는 새로운 대 침식전 부대의 창설을 준비하고 계시는 걸로 알고 있습니다만.","JPN":"そもそも長官も何人かの議員たちと一緒に、\\n秘密裏に管理局の干渉を受けない新しい対侵食戦部隊の創設を準備されていると聞いておりますが。","ENG":"It's my understanding that you've been discreetly working with a few senators and congressmen to prepare a new anti-Corruption unit free from the intervention of the Administration.","TWN":"我聽說長官您當初，就準備與幾位議員成立一支不受管理局干涉的反侵蝕戰部隊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전 그런 장관님에게 명분을 만들어 드리려는 겁니다.","JPN":"私はそんな長官に大義名分を作って差し上げようとしているのです。","ENG":"I'm merely trying to help you build your case for that.","TWN":"我想為長官創造一個契機。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......눈치가 제법 빠르군.","JPN":"……なかなか勘が鋭いな。","ENG":"You've got me.","TWN":"……妳還真是會察言觀色。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"어떻게 알아냈는지는 모르겠지만 확실히 자네 말대로야.","JPN":"どうやって調べたのか知らないが、確かに君の言う通りだ。","ENG":"I don't know how you found out about that, but it is as you said.","TWN":"雖然不清楚妳是怎麼知道的，但的確跟妳說得一樣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"이면세계라는 특수성을 걷어내고 보면 그들은 어느 날 갑자기 출처 불명의 신기술을 들고 온 수상한 자들일 뿐이지.","JPN":"裏世界という特殊性を取り除けば、彼らはある日突然出所不明の新技術を持ってきた不審者に過ぎない。","ENG":"Once you see past the special circumstance of the Counterside, these folks are nothing more than a suspicious lot who just showed up one day with a bunch of new technologies of unknown origin.","TWN":"除去異界這個特殊性質，他們就是群突然帶來不明高科技的可疑人員。"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"나 역시 그런 자들에게 인류의 안보를 계속 맡겨놓을 수는 없다고 생각하네.","JPN":"私もそんな者たちに人類の保安を任せてばかりはいられないと思う。","ENG":"Like you, I don't think we can leave the fate of our security to enigmatic folks like that.","TWN":"我還是覺得，我們不該一直把人類的安全交給那些人。"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"하지만 지금의 세계에서 관리국의 위상은 절대적이지.","JPN":"だが、今の世界で管理局の影響力は絶対的だ。","ENG":"However, the Administration enjoys absolute standing in the world today.","TWN":"但現在管理局的地位是絕對的。"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그들의 도움 없이는 함선용 이터니움 드라이브 하나 제대로 만들어 낼 수 없는 게 현실이야.","JPN":"彼らの支援なしには、艦船用のエタニウムドライブ一つもまともに作れないのが現状だ。","ENG":"Without their help, we can't build a single working Eternium drive for ships. This is our reality.","TWN":"如果沒有他們的幫助，我們甚至無法製造出一個艦船用的永恆之金引擎。"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"우리 합중국조차 연합함대라는 이름으로 관리국의 태스크포스 라이선스를 가져다 쓰고 있을 정도니까.","JPN":"我々合衆国ですら、連合艦隊という名で管理局のタスクフォースライセンスを借りているくらいだからな。","ENG":"Even our own great nation has signed a TASKFORCE licensing agreement with the Administration to operate our ships under the name of the Coalition Fleet.","TWN":"就連我們聯合國也要借聯合艦隊的名義，才能獲得並使用管理局特遣勢力執照。"},"stage":{"bg":"CCN_SHIP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"이런 상황에서 관리국과 결별하기 위한 부대를 창설하자고 하면 어떤 일이 벌어질 것 같나?","JPN":"こんな状況で管理局と別れるための部隊を創設しようとしたら、どんなことが起きると思う？","ENG":"What do you think would happen if we said we'll create a unit to put an end to our reliance on the Administration?","TWN":"如果這種情況下選擇和管理局分裂，妳覺得會發生什麼事？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"수많은 정치적인 견제를 받게 될 테고 자칫하면 정권이 바뀔 수도 있네.","JPN":"様々な政治的牽制を受けることはもちうろん、下手すると政権が変わってしまうかもしれない。","ENG":"We'll be met with all sorts of political hurdles. Our entire government may be placed at risk of replacement.","TWN":"我們將會受到無數的政治牽扯，稍有不慎政權都會被更換。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이미 그런 상황을 타개하기 위한 제물을 준비해두시지 않았습니까?","JPN":"そういう状況を打開するための生贄は、用意済みではないでしょうか？","ENG":"But haven't you already prepared the scapegoat to maneuver your way through such a quandary?","TWN":"您不是已經為了應對那種情況準備好犧牲品了嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......제물?","JPN":"……生贄？","ENG":"A scapegoat?","TWN":"……犧牲品？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전 바보가 아닙니다.","JPN":"私は愚かではありません。","ENG":"I'm not an idiot.","TWN":"我可不笨。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"세간에서는 영웅이라고 불러대지만 사실 저 같은 현장지휘관이 별을 두 개나 달고 있다는 건 조금......","JPN":"世間からは英雄だと呼ばれていますが、実は私のような現場指揮官が星を二つも付けていることは少し……","ENG":"Some may call me a hero, but it's rather strange for a field commander like me to sport two stars on her uniform...","TWN":"雖然世間都稱我為英雄，但實際上，像我這種現場指揮官只有兩顆星，這未免有點……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 많이 이상한 일이지요.","JPN":"いいえ、とてもおかしなことです。","ENG":"Actually, it's pretty much unheard of.","TWN":"不，是非常奇怪。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제 비정상적인 계급은 장관님의 입김이 많이 작용한 결과라고 추측하고 있습니다.","JPN":"私の異常な階級は、長官の息がかかった結果だと推測しています。","ENG":"I'm guessing my disproportionate rank is a result of your influence to a large degree.","TWN":"我猜這件事之所以會這麼不尋常，主要是長官的影響力起了作用。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"신설 부대에 대한 공격이 극에 달했을 때, 그 책임을 지고 전쟁 영웅이자 2성 장군인 제가 옷을 벗는다면......","JPN":"新設部隊への攻撃がピークに達した時、その責任を取って戦争の英雄であり2つ星将軍の私が辞職したら……","ENG":"If the pressure mounts up against the new unit, and the war-hero two-star bears the responsibility through resignation...","TWN":"如果他們對新部隊的攻擊到達了頂點，只要我負起責任，脫下這身代表著英雄和二星將軍的軍服……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"장관님은 충분히 그 역풍을 피해가실 수 있을 테니까요.","JPN":"長官は十分その逆風を避けられるのでしょう。","ENG":"You'll surely avoid that storm without a scratch.","TWN":"長官就可以完全避開輿論風波了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇지 않습니까?","JPN":"そうではありませんか？","ENG":"Isn't that right?","TWN":"不是嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......자네가 이 정도로 정치적인 감각까지 갖추고 있을 줄은 몰랐군.","JPN":"……君にそこまで政治的なセンスがあったとはな。","ENG":"I had no idea you'd possess such political acumen as well.","TWN":"……沒想到妳還是個當政治家的料啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"혹시 전역 후에 우리 당에서 의원으로 출마할 생각 없나?","JPN":"除隊後、うちの党で議員に立候補する気はないか？","ENG":"How would you like to run for Congress in my party after your military service?","TWN":"退伍後要不要來我們的黨部當議員？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"농담 마시죠. 군인은 정치에 관여하지 않습니다. 제 취향도 아니고 말이죠.","JPN":"冗談はおやめください。軍人は政治に関わりません。私の好みでもありませんし。","ENG":"Please don't even joke about that. Uniformed service members stay out of politics. Plus, it's not something I'd enjoy. No offense.","TWN":"請別開玩笑了。軍人不能參與政治活動，而且我也沒興趣。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"그거 아쉽군.","JPN":"それは残念だ。","ENG":"That's too bad.","TWN":"那還真是可惜。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"어쨌든 거기까지 예상했는데도 정말 이 일을 맡으려는 건가?","JPN":"とにかく、そこまで予想したのに本当にこの仕事を引き受けるつもりか？","ENG":"So you're still up for this job even after seeing that far ahead?","TWN":"不過妳都已經預想到這一步了，那妳還會想接下這份差事嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아시는지 모르겠지만 제 꿈은 하루라도 빨리 군을 떠나는 겁니다.","JPN":"ご存知かもしれませんが、私の夢は一日も早く軍を去ることです。","ENG":"I'm not sure if you're tracking, but my dream is to leave the military as soon as possible.","TWN":"也許您不知道，其實我的夢想是儘快離開軍隊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"조용한 동네에 작은 집을 구해서......","JPN":"静かな町で小さな家を買って……","ENG":"I'll get a small cottage in a quiet neighborhood...","TWN":"在安靜的社區裡找個小房子……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"한가하게 뜨개질이나 하며 노년을 보내는 거죠.","JPN":"のんびり編み物でもしながら余生を送るのです。","ENG":"And spend the rest of my old life knitting in peace.","TWN":"然後悠閒地織著毛衣度過晚年。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러니 제가 예편할 명분을 알아서 만들어 주신다는데 거절할 이유가 없습니다.","JPN":"なので、私が予備役に編入する名分を作ってくださるというのに、断る理由はありません。","ENG":"So I have no qualms about you shaping the situation for my honorable retirement.","TWN":"所以您都給我安排好退伍的契機了，我又有什麼理由拒絕呢。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"군을 떠나면서 마지막으로 인류를 위해 공헌할 수 있다면, 나중에 연금 타러 갈 때 부끄럽지는 않겠죠.","JPN":"軍を去る前に、最後に人類のために貢献できるのなら、胸を張って年金をもらえるはずです。","ENG":"If I can make one final contribution for mankind with my retirement, I won't feel as shameless when I cash my pension check.","TWN":"如果能在退伍前為人類做出貢獻，那麼以後領退休金也不會覺得不好意思了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"......자네 뜻이 그렇다면 나도 부담 없이 추진하도록 하지.","JPN":"……君の意志がそうであれば、私も遠慮なく進めるとしよう。","ENG":"If that's how you really feel, that takes the weight off my shoulders to proceed with this plan.","TWN":"……既然妳已經下定決心，那我就毫無顧慮地前進吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>공식적으로 자네가 제안한</color> 신설 부대는 전략 특수전 사령부 휘하의 7번째 부대가 될 거야.","JPN":"<color=#ffd34c>公式的に君が提案した</color>新設部隊は戦略特殊戦司令部指揮下の7番目の部隊になるだろう。","ENG":"The new unit that <color=#ffd34c>you officially recommended</color> will become the seventh unit subordinate to the Strategic Special Operations Command.","TWN":"<color=#ffd34c>由妳正式提議的</color> 新設部隊，將會成為戰略特種作戰司令部麾下的第7支部隊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"처음부터 정식 편제로 발령하긴 어렵고 한동안은 혹독한 평가 기간을 거쳐야겠지.","JPN":"最初から正式な編制として発令することは難しいから、しばらくは過酷な評価期間を経ることになるはずだ。","ENG":"It's unlikely we can launch it as a standing organization right from the start. You'll be subject to rigorous evaluation at the beginning as well.","TWN":"一開始就下令正式編制是有困難的，你們應該會經歷一段艱難的評估期。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINISTER_NPC_NULL_NULL","text":{"KOREA":"이름은...... 아마 델타 세븐 정도가 되겠군.","JPN":"名前はおそらく、デルタセブンになるんだろうな。","ENG":"As for the name... I guess it'll be something like Delta Seven.","TWN":"名字……大概就是第七三角洲部隊之類的吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......고전적이군요.","JPN":"……クラシックですね。","ENG":"Sounds very classic.","TWN":"……很經典啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제 마음에 드는 이름입니다.","JPN":"気に入りました。","ENG":"I like it.","TWN":"我喜歡這個名字。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};